use std::f64::consts::PI;

use rstest::*;

use fastnum::{udec256, UD256};

#[rstest]
#[trace]
#[case(0.0, udec256!(0))]
#[case(1234f64, udec256!(1234))]
#[case(1.0, udec256!(1.0))]
#[case(2.0, udec256!(2.0))]
#[case(3.0, udec256!(3.0))]
#[case(0.5, udec256!(0.5))]
#[case(0.25, udec256!(0.25))]
#[case(50000., udec256!(50000))]
#[case(0.1, udec256!(0.1000000000000000055511151231257827021181583404541015625))]
#[case(0.001, udec256!(0.001000000000000000020816681711721685132943093776702880859375))]
#[case(12.34, udec256!(12.339999999999999857891452847979962825775146484375))]
#[case(0.333333333333333333333333333333, udec256!(0.333333333333333314829616256247390992939472198486328125))]
#[case(5.0 * 0.03125, udec256!(0.15625))]
#[case(1.0 / 3.0, udec256!(0.333333333333333314829616256247390992939472198486328125))]
#[case(PI, udec256!(3.141592653589793115997963468544185161590576171875))]
#[case(PI * 10000.0f64, udec256!(31415.926535897931898944079875946044921875))]
#[case(PI * 30000.0f64, udec256!(94247.779607693795696832239627838134765625))]
#[case(f64::EPSILON, udec256!(2.220446049250313080847263336181640625e-16))]
#[case(3.0000000000000004, udec256!(3.000000000000000444089209850062616169452667236328125))]
// #[case(8.544283616667655e-306, udec256!(8.-306))]
// #[case(3e300, udec256!())]
#[case(50., udec256!(50))]
fn test_from_f64_ok(#[case] n: f64, #[case] expected: UD256) {
    let d = UD256::try_from(n).unwrap();
    assert_eq!(d, expected);

    let n = f64::from_bits(n.to_bits() | (1 << 63));
    let r = UD256::try_from(n);
    assert!(r.is_err());
}

#[rstest]
#[trace]
#[case(-0.0)]
#[case(-1.0)]
#[case(f64::NEG_INFINITY)]
#[case(f64::MIN)]
#[should_panic(expected = "(fastnum) number would be signed for unsigned type")]
fn test_from_f64_neg(#[case] n: f64) {
    let _ = UD256::try_from(n).unwrap();
}

#[rstest]
#[case(f64::MAX)]
#[case(f64::MIN_POSITIVE)]
#[should_panic(expected = "(fastnum) number too large to fit in target type")]
fn test_from_f64_overflow(#[case] n: f64) {
    let _ = UD256::try_from(n).unwrap();
}

#[rstest]
#[trace]
#[case(1.0e-308)]
#[case(4.940656e-324)]
#[should_panic(expected = "(fastnum) number too large to fit in target type")]
fn test_from_f64_subnormal(#[case] n: f64) {
    assert!(n.is_subnormal());
    let _ = UD256::try_from(n).unwrap();
}

