#[rstest]
#[trace]
#[case(f64::NAN)]
#[case(f64::from_bits(
    0b0111_1111_1111_1000_0000_0000_0000_0000_0000_0000_0000_0000_0000_0000_0000_0000
))]
#[should_panic(expected = "NaN")]
fn test_from_f64_nan(#[case] n: f64) {
    let _ = UD256::try_from(n).unwrap();
}

#[rstest]
#[trace]
#[should_panic(expected = "(fastnum) number is infinite")]
fn test_from_f64_infinity() {
    let n = f64::INFINITY;
    let _ = UD256::try_from(n).unwrap();
}
